-- H2O Benchmark: Temporal Quantile Queries for Elasticsearch SQL
-- 264 x 10-minute (600s) non-overlapping windows from 2024-01-01T00:00:00Z

-- T000: quantile window ending at 2024-01-01T00:10:00Z
SELECT PERCENTILE(v3, 95) AS p95_v3 FROM h2o_benchmark WHERE timestamp BETWEEN DATEADD('second', -600, CAST('2024-01-01T00:10:00Z' AS DATETIME)) AND CAST('2024-01-01T00:10:00Z' AS DATETIME) GROUP BY id1, id2 ORDER BY id1, id2;
